37	        private bool? _isStartZDirection;
38	        private List<PlaceInfo> _currentPlaceInfos = new();
39	        private BlockId? _previousSelectedBlockId;
40	
41	        private int _heightOffset;
42	
43	        public CommonBlockPlaceSystem(Camera mainCamera, IPlacementPreviewBlockGameObjectController previewBlockController, BlockGameObjectDataStore blockGameObjectDataStore, ILocalPlayerInventory localPlayerInventory)
44	        {
45	            _mainCamera = mainCamera;
46	            _previewBlockController = previewBlockController;
47	            _localPlayerInventory = localPlayerInventory;
48	            _blockPlacePointCalculator = new CommonBlockPlacePointCalculator(blockGameObjectDataStore);
49	            _autoConnectPreview = new ElectricWireAutoConnectPreview(mainCamera, blockGameObjectDataStore);
50	        }
51	        
52	        public void Enable()
53	        {
54	            _clickStartHeightOffset = -1;
55	        }
56	        public void Disable()
57	        {
58	            // デバッグモード時はプレビューを維持
59	            // Keep preview in debug mode
60	            if (!DebugParameters.GetValueOrDefaultBool(PlacePreviewKeepKey))
61	            {
62	                _previewBlockController.SetActive(false);
63	                _autoConnectPreview.Hide();
64	            }
65	
66	            // 連続設置状態をリセット
67	            _clickStartPosition = null;
68	            _isStartZDirection = null;
69	            _currentPlaceInfos.Clear();
70	        }
71	        
72	        public void ManualUpdate(PlaceSystemUpdateContext context)
73	        {
74	            UpdateHeightOffset();
75	            BlockDirectionControl();
76	            GroundClickControl(context);
77	            
78	            #region Internal
79	            
80	            void UpdateHeightOffset()
81	            {
82	                if (HybridInput.GetKeyDown(KeyCode.Q)) //TODO InputManagerに移す
83	                    _heightOffset--;
84	                else if (HybridInput.GetKeyDown(KeyCode.E)) _heightOffset++;
85	            }
86	            
87	            void BlockDirectionControl()
88	            {
89	                if (InputManager.Playable.BlockPlaceRotation.GetKeyDown)
90	                    // 東西南北の向きを変更する
91	                    _currentBlockDirection = _currentBlockDirection.HorizonRotation();
92	                
93	                //TODo シフトはインプットマネージャーに入れる
94	                if (HybridInput.GetKey(KeyCode.LeftShift) && InputManager.Playable.BlockPlaceRotation.GetKeyDown)
95	                    _currentBlockDirection = _currentBlockDirection.VerticalRotation();
96	            }
97	            
98	            #endregion
99	        }
100	        
101	        
102	        private void GroundClickControl(PlaceSystemUpdateContext context)
103	        {
104	            // ビルドメニューの選択ブロックが変わったら連続設置状態をリセット
105	            // Reset the continuous placement state when the build-menu selected block changes
106	            if (_previousSelectedBlockId != context.SelectedBlockId)
107	            {
108	                _clickStartPosition = null;
109	                _clickStartHeightOffset = _heightOffset;
110	            }
111	            _previousSelectedBlockId = context.SelectedBlockId;
112	
113	            //基本はプレビュー非表示
114	            _previewBlockController.SetActive(false);
115	
116	            // ブロック設置用のrayが当たっているか、当たっていたら設置位置を取得する
117	            var holdingBlockMaster = MasterHolder.BlockMaster.GetBlockMaster(context.SelectedBlockId.Value);
118	            if (!TryGetRayHitBlockPosition(_mainCamera, _heightOffset, _currentBlockDirection, holdingBlockMaster, out var placePoint, out var boundingBoxSurface)) { _autoConnectPreview.Hide(); return; }
119	
120	            // 設置可能な距離かどうか
121	            if (!IsBlockPlaceableDistance(PlaceableMaxDistance)) { _autoConnectPreview.Hide(); return; }
122	            
123	            _previewBlockController.SetActive(true);
124	            
125	            //クリックされてたらUIがゲームスクリーンの時にホットバーにあるブロックの設置
126	            if (InputManager.Playable.ScreenLeftClick.GetKeyDown && !EventSystem.current.IsPointerOverGameObject())
127	            {
128	                _clickStartPosition = placePoint;
129	                _clickStartHeightOffset = _heightOffset;
130	            }
131	            
132	            //プレビュー表示と地面との接触を取得する
133	            //display preview and get collision with ground
134	            SetCurrentPlaceInfo();
135	
136	            var blockGroundOverlapList = _previewBlockController.SetPreviewAndGroundDetect(_currentPlaceInfos, holdingBlockMaster);
137	
138	            // 地面との接触でPlaceableを更新
139	            // Update placeable based on ground collision
140	            for (var i = 0; i < blockGroundOverlapList.Count; i++)
141	            {
142	                // 地面と接触していたら設置不可
143	                // if collision with ground, cannot place
144	                if (blockGroundOverlapList[i])
145	                {
146	                    _currentPlaceInfos[i].Placeable = false;
147	                }
148	            }
149	
150	            // 地面フィルタ後にアイテム数チェック（地面に埋まったブロックがアイテム枠を消費しないようにする）
151	            // Check item count after ground filtering (so ground-blocked cells don't consume item quota)
152	            MarkInsufficientItemPreviewsAsNotPlaceable();
153	
154	            // 各セルの自動接続を評価し表示更新
155	            // Evaluate auto-connect per cell and update the preview
156	            var wirePlaceable = _autoConnectPreview.ApplyAutoConnect(_currentPlaceInfos, context.SelectedBlockId.Value, _currentBlockDirection, _localPlayerInventory, placePoint);
157	
158	            // 最終的なPlaceable状態でプレビュー色を更新
159	            // Update preview colors based on the final Placeable state
160	            _previewBlockController.UpdatePlaceableColors(_currentPlaceInfos);
161	
162	            // 設置するブロックをサーバーに送信
163	            // send block place info to server
164	            PlaceBlock();
165	            
166	            #region Internal
167	            
168	            bool IsBlockPlaceableDistance(float maxDistance)
169	            {
170	                var placePosition = (Vector3)placePoint;
171	                var playerPosition = PlayerSystemContainer.Instance.PlayerObjectController.Position;
172	                
173	                return Vector3.Distance(playerPosition, placePosition) <= maxDistance;
174	            }
175	            
176	            void SetCurrentPlaceInfo()
177	            {
178	                if (_clickStartPosition.HasValue)
179	                {
180	                    if (_clickStartPosition.Value == placePoint)
181	                    {
182	                        _isStartZDirection = null;
183	                    }
184	                    else if (!_isStartZDirection.HasValue)
185	                    {
186	                        _isStartZDirection = Mathf.Abs(placePoint.z - _clickStartPosition.Value.z) > Mathf.Abs(placePoint.x - _clickStartPosition.Value.x);
187	                    }
188	                    
189	                    _currentPlaceInfos = _blockPlacePointCalculator.CalculatePoint(_clickStartPosition.Value, placePoint, _isStartZDirection ?? true, _currentBlockDirection, holdingBlockMaster);
190	                }
191	                else
192	                {
193	                    _isStartZDirection = null;
194	                    _currentPlaceInfos = _blockPlacePointCalculator.CalculatePoint(placePoint, placePoint, true, _currentBlockDirection, holdingBlockMaster);
195	                }
196	            }
197	            
198	            void PlaceBlock()
199	            {
200	                if (!InputManager.Playable.ScreenLeftClick.GetKeyUp) return;
201	
202	                // デバッグモード時は送信しない
203	                // Skip sending in debug mode
204	                if (DebugParameters.GetValueOrDefaultBool(PlacePreviewKeepKey)) return;
205	
206	                // マウスを離したので連続設置状態は解除する（設置有無に関わらず）
207	                // Clear the continuous-placement state on mouse release (regardless of whether we place)
208	                _heightOffset = _clickStartHeightOffset;
209	                _clickStartPosition = null;
210	
211	                // 電線不足で全セル設置不可なら設置クリックを無効化する（サーバーも拒否するが先回りで抑止）
212	                // Disable the placement click when no cell is placeable due to wire shortage (server also rejects, but block early)
213	                if (!wirePlaceable) return;
214	
215	                SendPlaceBlockProtocol(_currentPlaceInfos);
216	
217	                // 設置でワールドとインベントリが変わるため、自動接続の評価キャッシュを破棄する
218	                // Placement changes the world and inventory, so drop the auto-connect evaluation cache
219	                _autoConnectPreview.Hide();
220	            }
221	
222	            void MarkInsufficientItemPreviewsAsNotPlaceable()
223	            {
224	                // 建設コストで賄えるセル数まで設置可にする
225	                // Allow placement up to the affordable cell count
226	                var blockMaster = MasterHolder.BlockMaster.GetBlockMaster(context.SelectedBlockId.Value);
227	                var affordableCellCount = ConstructionCostPreviewCalculator.CalculateAffordableCellCount(blockMaster.RequiredItems, _localPlayerInventory);
228	
229	                var placeableCount = 0;
230	                for (var i = 0; i < _currentPlaceInfos.Count; i++)
231	                {
232	                    if (!_currentPlaceInfos[i].Placeable) continue;
233	                    placeableCount++;
234	                    if (placeableCount > affordableCellCount)
235	                    {
236	                        _currentPlaceInfos[i].Placeable = false;
237	                    }
238	                }
239	            }
